prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org ?created WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "3c08e52742754da6a4065fc5787131dc" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  OPTIONAL { ?model tai:modelCreated ?created . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?def ?choreo ?choreoName ?taskCount WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?def tai:belongsTo ?model .
  ?def a bboExt:Definitions .
  ?choreo tai:belongsTo ?def .
  ?choreo a bboExt:Choreography .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL {
    SELECT ?choreo2 (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
      ?task a bboExt:ChoreographyTask .
      ?task tai:belongsTo ?choreo2 .
    }
    GROUP BY ?choreo2
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?startName ?startInterrupting ?endName WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  ?def tai:belongsTo ?model .
  ?def a bboExt:Definitions .
  ?choreo tai:belongsTo ?def .
  ?choreo a bboExt:Choreography .
  OPTIONAL {
    ?startEvent a bboExt:StartEvent .
    ?startEvent tai:belongsTo ?choreo .
    OPTIONAL { ?startEvent bbo:name ?startName . }
    OPTIONAL { ?startEvent bboExt:isInterrupting ?startInterrupting . }
  }
  OPTIONAL {
    ?endEvent a bboExt:EndEvent .
    ?endEvent tai:belongsTo ?choreo .
    OPTIONAL { ?endEvent bbo:name ?endName . }
  }
}
LIMIT 25
